/**
 * Judge Assignment Server Functions for TanStack Start
 * Manages judge-to-heat assignments, lane assignments, and version management.
 * Port from wodsmith/src/server/judge-assignments.ts and wodsmith/src/actions/judge-assignment-actions.ts
 */

import { createServerFn } from "@tanstack/react-start"
import { and, asc, desc, eq } from "drizzle-orm"
import { z } from "zod"
import { getDb } from "@/db"
import type { JudgeAssignmentVersion, JudgeHeatAssignment } from "@/db/schema"
import {
  competitionHeatsTable,
  competitionJudgeRotationsTable,
  competitionsTable,
  competitionVenuesTable,
  judgeAssignmentVersionsTable,
  judgeHeatAssignmentsTable,
  LANE_SHIFT_PATTERN,
  programmingTracksTable,
  trackWorkoutsTable,
} from "@/db/schema"
import { TEAM_PERMISSIONS } from "@/db/schemas/teams"
import { requireTeamPermission } from "@/utils/team-auth"

// ============================================================================
// Types
// ============================================================================

export interface PublishRotationsParams {
  trackWorkoutId: string
  publishedBy: string // User ID
  notes?: string
  teamId: string // For permission check
}

export interface RollbackToVersionParams {
  versionId: string
  teamId: string // For permission check
}

type MaterializedAssignment = Record<string, unknown> & {
  heatId: string
  membershipId: string
  rotationId: string
  laneNumber: number
  position: "judge" // Judge rotations always create judge assignments
}

// ============================================================================
// Input Schemas
// ============================================================================

const publishRotationsSchema = z.object({
  teamId: z.string().min(1, "Team ID is required"),
  trackWorkoutId: z.string().min(1, "Event ID is required"),
  publishedBy: z.string().min(1, "Publisher user ID is required"),
  notes: z.string().max(1000, "Notes too long").optional(),
})

const getActiveVersionSchema = z.object({
  trackWorkoutId: z.string().min(1, "Event ID is required"),
})

const getVersionHistorySchema = z.object({
  trackWorkoutId: z.string().min(1, "Event ID is required"),
})

const rollbackToVersionSchema = z.object({
  teamId: z.string().min(1, "Team ID is required"),
  versionId: z.string().min(1, "Version ID is required"),
})

const getAssignmentsForVersionSchema = z.object({
  versionId: z.string().min(1, "Version ID is required"),
})

const getActiveAssignmentsSchema = z.object({
  trackWorkoutId: z.string().min(1, "Event ID is required"),
})

// ============================================================================
// Internal Helper Functions
// ============================================================================

/**
 * Calculate lane number based on shift pattern
 */
function calculateLane(
  startingLane: number,
  heatIndex: number,
  laneShiftPattern: string,
  maxLanes: number,
): number {
  switch (laneShiftPattern) {
    case LANE_SHIFT_PATTERN.STAY:
      return startingLane

    case LANE_SHIFT_PATTERN.SHIFT_RIGHT:
      // Move right (lane + 1), wrap around
      return ((startingLane - 1 + heatIndex) % maxLanes) + 1

    default:
      return startingLane
  }
}

/**
 * Expand rotations into individual heat+lane assignments
 */
async function materializeRotations(
  trackWorkoutId: string,
  maxLanes: number,
): Promise<MaterializedAssignment[]> {
  const db = getDb()
  const assignments: MaterializedAssignment[] = []

  // Get all rotations for this event
  const rotations = await db.query.competitionJudgeRotationsTable.findMany({
    where: eq(competitionJudgeRotationsTable.trackWorkoutId, trackWorkoutId),
  })

  // Get all heats for this event, sorted by heat number
  const heats = await db
    .select({
      id: competitionHeatsTable.id,
      heatNumber: competitionHeatsTable.heatNumber,
    })
    .from(competitionHeatsTable)
    .where(eq(competitionHeatsTable.trackWorkoutId, trackWorkoutId))
    .orderBy(asc(competitionHeatsTable.heatNumber))

  // Build heat number -> ID map
  const heatMap = new Map(heats.map((h) => [h.heatNumber, h.id]))

  // Expand each rotation, deduplicating by (heatId, membershipId) to avoid
  // unique constraint violations if rotations overlap on the same heat+judge
  const seen = new Set<string>()

  for (const rotation of rotations) {
    for (let i = 0; i < rotation.heatsCount; i++) {
      const heatNumber = rotation.startingHeat + i
      const heatId = heatMap.get(heatNumber)

      if (!heatId) {
        console.warn(
          `Heat ${heatNumber} not found for rotation ${rotation.id}, skipping`,
        )
        continue
      }

      const key = `${heatId}:${rotation.membershipId}`
      if (seen.has(key)) {
        console.warn(
          `Duplicate assignment for heat ${heatNumber}, judge ${rotation.membershipId} from rotation ${rotation.id}, skipping`,
        )
        continue
      }
      seen.add(key)

      const laneNumber = calculateLane(
        rotation.startingLane,
        i,
        rotation.laneShiftPattern,
        maxLanes,
      )

      assignments.push({
        heatId,
        membershipId: rotation.membershipId,
        rotationId: rotation.id,
        laneNumber,
        position: "judge",
      })
    }
  }

  return assignments
}

// ============================================================================
// Query Functions
// ============================================================================

/**
 * Get the currently active version for an event.
 * Returns null if no version has been published yet.
 */
export const getActiveVersionFn = createServerFn({ method: "GET" })
  .inputValidator((data: unknown) => getActiveVersionSchema.parse(data))
  .handler(async ({ data }): Promise<JudgeAssignmentVersion | null> => {
    const db = getDb()
    const version = await db.query.judgeAssignmentVersionsTable.findFirst({
      where: and(
        eq(judgeAssignmentVersionsTable.trackWorkoutId, data.trackWorkoutId),
        eq(judgeAssignmentVersionsTable.isActive, true),
      ),
    })

    return version ?? null
  })

/**
 * Get version history for an event, newest first
 */
export const getVersionHistoryFn = createServerFn({ method: "GET" })
  .inputValidator((data: unknown) => getVersionHistorySchema.parse(data))
  .handler(async ({ data }): Promise<JudgeAssignmentVersion[]> => {
    const db = getDb()
    return db.query.judgeAssignmentVersionsTable.findMany({
      where: eq(
        judgeAssignmentVersionsTable.trackWorkoutId,
        data.trackWorkoutId,
      ),
      orderBy: desc(judgeAssignmentVersionsTable.version),
      with: {
        publishedByUser: {
          columns: {
            id: true,
            firstName: true,
            lastName: true,
            email: true,
          },
        },
      },
    })
  })

/**
 * Get all assignments for a specific version
 */
export const getAssignmentsForVersionFn = createServerFn({ method: "GET" })
  .inputValidator((data: unknown) => getAssignmentsForVersionSchema.parse(data))
  .handler(async ({ data }): Promise<JudgeHeatAssignment[]> => {
    const db = getDb()
    return db.query.judgeHeatAssignmentsTable.findMany({
      where: eq(judgeHeatAssignmentsTable.versionId, data.versionId),
      with: {
        heat: true,
        membership: {
          with: {
            user: {
              columns: {
                id: true,
                firstName: true,
                lastName: true,
              },
            },
          },
        },
        rotation: true,
      },
      orderBy: [
        asc(judgeHeatAssignmentsTable.heatId),
        asc(judgeHeatAssignmentsTable.laneNumber),
      ],
    })
  })

/**
 * Get assignments for the active version of an event
 */
export const getActiveAssignmentsFn = createServerFn({ method: "GET" })
  .inputValidator((data: unknown) => getActiveAssignmentsSchema.parse(data))
  .handler(async ({ data }): Promise<JudgeHeatAssignment[]> => {
    const db = getDb()

    // First get the active version
    const activeVersion = await db.query.judgeAssignmentVersionsTable.findFirst(
      {
        where: and(
          eq(judgeAssignmentVersionsTable.trackWorkoutId, data.trackWorkoutId),
          eq(judgeAssignmentVersionsTable.isActive, true),
        ),
      },
    )

    if (!activeVersion) {
      return []
    }

    // Then get assignments for that version
    return db.query.judgeHeatAssignmentsTable.findMany({
      where: eq(judgeHeatAssignmentsTable.versionId, activeVersion.id),
      with: {
        heat: true,
        membership: {
          with: {
            user: {
              columns: {
                id: true,
                firstName: true,
                lastName: true,
              },
            },
          },
        },
        rotation: true,
      },
      orderBy: [
        asc(judgeHeatAssignmentsTable.heatId),
        asc(judgeHeatAssignmentsTable.laneNumber),
      ],
    })
  })

// ============================================================================
// Mutation Functions
// ============================================================================

/**
 * Publish rotations as a new version.
 * Creates a new version, materializes all rotations into judge_heat_assignments,
 * and deactivates the previous version.
 */
export const publishRotationsFn = createServerFn({ method: "POST" })
  .inputValidator((data: unknown) => publishRotationsSchema.parse(data))
  .handler(async ({ data }): Promise<JudgeAssignmentVersion> => {
    // Permission check
    await requireTeamPermission(
      data.teamId,
      TEAM_PERMISSIONS.MANAGE_COMPETITIONS,
    )

    const db = getDb()

    // Get event info to find maxLanes - using manual join to get competition venues
    const result = await db
      .select({
        competitionId: programmingTracksTable.competitionId,
        venues: competitionVenuesTable,
      })
      .from(trackWorkoutsTable)
      .innerJoin(
        programmingTracksTable,
        eq(trackWorkoutsTable.trackId, programmingTracksTable.id),
      )
      .innerJoin(
        competitionsTable,
        eq(programmingTracksTable.competitionId, competitionsTable.id),
      )
      .innerJoin(
        competitionVenuesTable,
        eq(competitionsTable.id, competitionVenuesTable.competitionId),
      )
      .where(eq(trackWorkoutsTable.id, data.trackWorkoutId))

    if (result.length === 0) {
      throw new Error("Event or competition not found")
    }

    // Find max lanes from venues
    const maxLanes = result.reduce(
      (max: number, row) => Math.max(max, row.venues.laneCount),
      3,
    )

    // Get next version number
    const versions = await db.query.judgeAssignmentVersionsTable.findMany({
      where: eq(
        judgeAssignmentVersionsTable.trackWorkoutId,
        data.trackWorkoutId,
      ),
      orderBy: desc(judgeAssignmentVersionsTable.version),
    })
    const nextVersion =
      versions.length > 0 ? (versions[0]?.version ?? 0) + 1 : 1

    // Materialize all rotations (read-only, before transaction)
    const materializedAssignments = await materializeRotations(
      data.trackWorkoutId,
      maxLanes,
    )

    const { createJudgeAssignmentVersionId } = await import("@/db/schema")
    const newVersionId = createJudgeAssignmentVersionId()

    // Use transaction for atomic version switch + assignment creation
    const newVersion = await db.transaction(async (tx) => {
      // Deactivate previous versions
      await tx
        .update(judgeAssignmentVersionsTable)
        .set({ isActive: false, updatedAt: new Date() })
        .where(
          eq(judgeAssignmentVersionsTable.trackWorkoutId, data.trackWorkoutId),
        )

      // Create new version
      await tx.insert(judgeAssignmentVersionsTable).values({
        id: newVersionId,
        trackWorkoutId: data.trackWorkoutId,
        version: nextVersion,
        publishedBy: data.publishedBy,
        notes: data.notes ?? null,
        isActive: true,
      })

      const version = await tx.query.judgeAssignmentVersionsTable.findFirst({
        where: eq(judgeAssignmentVersionsTable.id, newVersionId),
      })

      if (!version) {
        throw new Error("Failed to create version")
      }

      // Bulk insert all assignments in a single query (MySQL has no param limit)
      if (materializedAssignments.length > 0) {
        await tx.insert(judgeHeatAssignmentsTable).values(
          materializedAssignments.map((a) => ({
            heatId: a.heatId,
            membershipId: a.membershipId,
            rotationId: a.rotationId,
            laneNumber: a.laneNumber,
            position: a.position,
            versionId: version.id,
            isManualOverride: false,
          })),
        )
      }

      return version
    })

    return newVersion
  })

/**
 * Rollback to a different version by setting it as active
 */
export const rollbackToVersionFn = createServerFn({ method: "POST" })
  .inputValidator((data: unknown) => rollbackToVersionSchema.parse(data))
  .handler(async ({ data }): Promise<JudgeAssignmentVersion> => {
    const db = getDb()

    // Get the version to rollback to
    const targetVersion = await db.query.judgeAssignmentVersionsTable.findFirst(
      {
        where: eq(judgeAssignmentVersionsTable.id, data.versionId),
      },
    )

    if (!targetVersion) {
      throw new Error("Version not found")
    }

    // Permission check
    await requireTeamPermission(
      data.teamId,
      TEAM_PERMISSIONS.MANAGE_COMPETITIONS,
    )

    // Use transaction for atomic version switch
    const updatedVersion = await db.transaction(async (tx) => {
      // Deactivate all versions for this event
      await tx
        .update(judgeAssignmentVersionsTable)
        .set({ isActive: false, updatedAt: new Date() })
        .where(
          eq(
            judgeAssignmentVersionsTable.trackWorkoutId,
            targetVersion.trackWorkoutId,
          ),
        )

      // Activate the target version
      await tx
        .update(judgeAssignmentVersionsTable)
        .set({ isActive: true, updatedAt: new Date() })
        .where(eq(judgeAssignmentVersionsTable.id, data.versionId))

      const version = await tx.query.judgeAssignmentVersionsTable.findFirst({
        where: eq(judgeAssignmentVersionsTable.id, data.versionId),
      })

      if (!version) {
        throw new Error("Failed to activate version")
      }

      return version
    })

    return updatedVersion
  })

"use client"

// @lat: [[organizer-dashboard#Volunteers#Judge Scheduling]]

import { Link, useNavigate } from "@tanstack/react-router"
import { CalendarDays, ClipboardList, Search, Settings2 } from "lucide-react"
import { useEffect, useMemo, useState } from "react"
import { toast } from "sonner"
import { OrganizerEmptyState } from "@/components/organizer/empty-state"
import { Button } from "@/components/ui/button"
import { Card, CardContent } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import {
  Sheet,
  SheetContent,
  SheetDescription,
  SheetHeader,
  SheetTitle,
  SheetTrigger,
} from "@/components/ui/sheet"
import type {
  CompetitionJudgeRotation,
  JudgeAssignmentVersion,
} from "@/db/schema"
import type { LaneShiftPattern } from "@/db/schemas/volunteers"
import { canUseHeatScheduling } from "@/lib/competitions/scheduling-check-in-gates"
import { calculateCoverage } from "@/lib/judge-rotation-utils"
import type { HeatWithAssignments } from "@/server-fns/competition-heats-fns"
import type { CompetitionWorkout } from "@/server-fns/competition-workouts-fns"
import {
  getActiveVersionFn,
  getVersionHistoryFn,
  rollbackToVersionFn,
} from "@/server-fns/judge-assignment-fns"
import {
  getJudgeHeatAssignmentsFn,
  type JudgeHeatAssignment,
  type JudgeVolunteerInfo,
} from "@/server-fns/judge-scheduling-fns"
import { formatTrackOrder } from "@/utils/format-track-order"

import { DraggableJudge } from "./draggable-judge"
import { EventDefaultsEditor } from "./event-defaults-editor"
import { JudgeHeatCard } from "./judge-heat-card"
import { JudgeOverview } from "./judge-overview"
import { RotationOverview } from "./rotation-overview"
import { RotationTimeline } from "./rotation-timeline"

/** Per-event defaults for judge rotations */
interface EventDefaults {
  defaultHeatsCount: number | null
  defaultLaneShiftPattern: LaneShiftPattern | null
  minHeatBuffer: number | null
}

/** Override callbacks for cohost access to judge scheduling mutations */
export interface JudgeSchedulingOverrides {
  /** Override for rollbackToVersionFn */
  rollbackToVersion?: (args: {
    data: { versionId: string; teamId: string }
  }) => Promise<JudgeAssignmentVersion>
  /** Override for createJudgeRotationFn */
  createJudgeRotation?: (args: { data: Record<string, unknown> }) => Promise<{
    success: boolean
    data: CompetitionJudgeRotation
  }>
  /** Override for updateJudgeRotationFn */
  updateJudgeRotation?: (args: { data: Record<string, unknown> }) => Promise<{
    success: boolean
    data: CompetitionJudgeRotation
  }>
  /** Override for deleteJudgeRotationFn */
  deleteJudgeRotation?: (args: {
    data: Record<string, unknown>
  }) => Promise<{ success: boolean }>
  /** Override for updateEventDefaultsFn */
  updateEventDefaults?: (args: {
    data: Record<string, unknown>
  }) => Promise<{ success: boolean }>
  /** Override for batchCreateRotationsFn */
  batchCreateRotations?: (args: { data: Record<string, unknown> }) => Promise<{
    success: boolean
    data: { rotationIds: string[]; rotations: CompetitionJudgeRotation[] }
  }>
  /** Override for deleteVolunteerRotationsFn */
  deleteVolunteerRotations?: (args: {
    data: Record<string, unknown>
  }) => Promise<{ success: boolean; data: { deletedCount: number } }>
  /** Override for batchDeleteRotationsFn */
  batchDeleteRotations?: (args: {
    data: Record<string, unknown>
  }) => Promise<{ success: boolean; data: { deletedCount: number } }>
  /** Override for batchUpdateVolunteerRotationsFn */
  batchUpdateVolunteerRotations?: (args: {
    data: Record<string, unknown>
  }) => Promise<{
    success: boolean
    data: { rotationIds: string[]; rotations: CompetitionJudgeRotation[] }
  }>
  /** Override for publishRotationsFn */
  publishRotations?: (args: {
    data: Record<string, unknown>
  }) => Promise<JudgeAssignmentVersion>
  /** Override for adjustRotationsForOccupiedLanesFn */
  adjustRotationsForOccupiedLanes?: (args: {
    data: Record<string, unknown>
  }) => Promise<{
    success: boolean
    data: { deletedCount: number; createdCount: number; unchangedCount: number }
  }>
}

interface JudgeSchedulingContainerProps {
  competitionId: string
  competitionSlug: string
  organizingTeamId: string
  competitionType: "in-person" | "online"
  events: CompetitionWorkout[]
  heats: HeatWithAssignments[]
  judges: JudgeVolunteerInfo[]
  judgeAssignments: JudgeHeatAssignment[]
  rotations: CompetitionJudgeRotation[]
  /** Map of event ID to event defaults */
  eventDefaultsMap: Map<string, EventDefaults>
  /** Map of event ID to version history */
  versionHistoryMap: Map<string, JudgeAssignmentVersion[]>
  /** Map of event ID to active version */
  activeVersionMap: Map<string, JudgeAssignmentVersion | null>
  /** Competition-level default heats per rotation */
  competitionDefaultHeats: number
  /** Competition-level default lane shift pattern */
  competitionDefaultPattern: LaneShiftPattern
  /** Currently selected event ID (from URL) */
  selectedEventId: string
  /** Callback when event selection changes */
  onEventChange: (eventId: string) => void
  /**
   * Hide the container's built-in event selector. Useful when the
   * parent page already renders one (e.g. the AI judge scheduling page
   * has its own selector that drives both the agent and this editor).
   */
  hideEventSelector?: boolean
  /**
   * Optional slot rendered above the Rotations section. The AI
   * scheduling page uses this for the activity log narration that
   * appears as the agent works.
   */
  rotationsHeaderSlot?: React.ReactNode
  /**
   * Optional slot rendered next to the Publish button in the rotation
   * overview row. The AI scheduling page uses this for the
   * "Generate AI suggestions" button so it sits next to Publish (the
   * primary CTA) instead of floating above the section.
   */
  rotationOverviewActionsSlot?: React.ReactNode
  /** Optional override callbacks for cohost routes */
  overrides?: JudgeSchedulingOverrides
}

/**
 * Main container for judge scheduling.
 * Shows event selector, overview, available judges panel, and heat cards.
 */
export function JudgeSchedulingContainer({
  competitionId,
  competitionSlug,
  organizingTeamId,
  competitionType,
  events,
  heats,
  judges,
  judgeAssignments: initialAssignments,
  rotations: initialRotations,
  eventDefaultsMap,
  versionHistoryMap,
  activeVersionMap,
  competitionDefaultHeats,
  competitionDefaultPattern,
  selectedEventId,
  onEventChange,
  hideEventSelector = false,
  rotationsHeaderSlot,
  rotationOverviewActionsSlot,
  overrides,
}: JudgeSchedulingContainerProps) {
  const navigate = useNavigate()
  const hasHeatScheduling = canUseHeatScheduling(competitionType)
  const [assignments, setAssignments] =
    useState<JudgeHeatAssignment[]>(initialAssignments)
  const [selectedJudgeIds, setSelectedJudgeIds] = useState<Set<string>>(
    new Set(),
  )
  const [selectedVersionId, setSelectedVersionId] = useState<string | null>(
    null,
  )
  const [isRollingBack, setIsRollingBack] = useState(false)
  const [isFetchingAssignments, setIsFetchingAssignments] = useState(false)
  const [filterEmptyLanes, setFilterEmptyLanes] = useState(true)
  const [availableJudgeSearch, setAvailableJudgeSearch] = useState("")

  // Get heats for selected event
  const eventHeats = useMemo(
    () =>
      heats
        .filter((h) => h.trackWorkoutId === selectedEventId)
        .sort((a, b) => a.heatNumber - b.heatNumber),
    [heats, selectedEventId],
  )

  // Get max lanes from venue or default to 10
  const maxLanes = useMemo(() => {
    const venueWithLanes = eventHeats.find((h) => h.venue?.laneCount)
    return venueWithLanes?.venue?.laneCount ?? 10
  }, [eventHeats])

  // Get assigned judge IDs for current event
  const assignedJudgeIds = useMemo(() => {
    const eventHeatIds = new Set(eventHeats.map((h) => h.id))
    return new Set(
      assignments
        .filter((a) => eventHeatIds.has(a.heatId))
        .map((a) => a.membershipId),
    )
  }, [eventHeats, assignments])

  // Get unassigned judges for current event
  const unassignedJudges = useMemo(
    () => judges.filter((j) => !assignedJudgeIds.has(j.membershipId)),
    [judges, assignedJudgeIds],
  )

  // Get all judges sorted by total heat assignment count (ascending - least assigned first)
  const judgesByAssignmentCount = useMemo(() => {
    // Count assignments per judge across ALL heats (not just current event)
    const assignmentCounts = new Map<string, number>()
    for (const judge of judges) {
      assignmentCounts.set(judge.membershipId, 0)
    }
    for (const assignment of assignments) {
      const membershipId = assignment.membershipId
      if (!membershipId) continue
      const count = assignmentCounts.get(membershipId) ?? 0
      assignmentCounts.set(membershipId, count + 1)
    }

    // Sort judges by assignment count (ascending)
    return [...judges]
      .map((judge) => ({
        ...judge,
        assignmentCount: assignmentCounts.get(judge.membershipId) ?? 0,
      }))
      .sort((a, b) => a.assignmentCount - b.assignmentCount)
  }, [judges, assignments])

  // Filter judges by search query
  const filteredJudgesByAssignmentCount = useMemo(() => {
    if (!availableJudgeSearch.trim()) return judgesByAssignmentCount
    const query = availableJudgeSearch.toLowerCase().trim()
    return judgesByAssignmentCount.filter((judge) => {
      const fullName =
        `${judge.firstName ?? ""} ${judge.lastName ?? ""}`.toLowerCase()
      return fullName.includes(query)
    })
  }, [judgesByAssignmentCount, availableJudgeSearch])

  // Get rotations for selected event - track locally to update on changes
  const initialEventRotations = useMemo(
    () => initialRotations.filter((r) => r.trackWorkoutId === selectedEventId),
    [initialRotations, selectedEventId],
  )
  const [eventRotations, setEventRotations] = useState(initialEventRotations)

  // Sync when event changes or initial data changes
  useEffect(() => {
    setEventRotations(initialEventRotations)
  }, [initialEventRotations])

  // Get selected event details
  const selectedEvent = useMemo(
    () => events.find((e) => e.id === selectedEventId),
    [events, selectedEventId],
  )

  // Get version data for selected event - track locally to update on publish
  const initialVersionHistory = useMemo(
    () => versionHistoryMap.get(selectedEventId) ?? [],
    [versionHistoryMap, selectedEventId],
  )
  const initialActiveVersion = useMemo(
    () => activeVersionMap.get(selectedEventId) ?? null,
    [activeVersionMap, selectedEventId],
  )
  const [eventVersionHistory, setEventVersionHistory] = useState(
    initialVersionHistory,
  )
  const [eventActiveVersion, setEventActiveVersion] =
    useState(initialActiveVersion)

  // Sync when event changes
  useEffect(() => {
    setEventVersionHistory(initialVersionHistory)
    setEventActiveVersion(initialActiveVersion)
  }, [initialVersionHistory, initialActiveVersion])

  // Auto-select active version when event changes
  useEffect(() => {
    if (eventActiveVersion) {
      setSelectedVersionId(eventActiveVersion.id)
    } else {
      setSelectedVersionId(null)
    }
  }, [eventActiveVersion])

  // Refresh version data after publishing
  async function refreshVersionData() {
    try {
      const [historyResult, activeResult] = await Promise.all([
        getVersionHistoryFn({ data: { trackWorkoutId: selectedEventId } }),
        getActiveVersionFn({ data: { trackWorkoutId: selectedEventId } }),
      ])
      if (historyResult) {
        setEventVersionHistory(historyResult)
      }
      setEventActiveVersion(activeResult)

      // Also fetch assignments for the new active version
      if (activeResult) {
        setSelectedVersionId(activeResult.id)
        const assignmentsResult = await getJudgeHeatAssignmentsFn({
          data: { trackWorkoutId: selectedEventId, versionId: activeResult.id },
        })
        if (assignmentsResult) {
          setAssignments((prev) => {
            // Remove old assignments for this event, add new ones
            const eventHeatIds = new Set(eventHeats.map((h) => h.id))
            const withoutEvent = prev.filter((a) => !eventHeatIds.has(a.heatId))
            return [...withoutEvent, ...assignmentsResult]
          })
        }
      }
    } catch (err) {
      console.error("Failed to refresh version data:", err)
    }
  }

  // Handle version change
  async function handleVersionChange(versionId: string) {
    if (versionId === eventActiveVersion?.id) {
      // Already active, just update UI
      setSelectedVersionId(versionId)
      return
    }

    // Rollback to different version
    setIsRollingBack(true)
    try {
      const rollbackFn = overrides?.rollbackToVersion ?? rollbackToVersionFn
      const result = await rollbackFn({
        data: {
          teamId: organizingTeamId,
          versionId,
        },
      })

      if (result) {
        toast.success("Version activated successfully")
        setSelectedVersionId(versionId)

        // Fetch assignments for the new version
        setIsFetchingAssignments(true)
        try {
          const assignmentsResult = await getJudgeHeatAssignmentsFn({
            data: { trackWorkoutId: selectedEventId, versionId },
          })
          if (assignmentsResult) {
            setAssignments((prev) => {
              // Remove old assignments for this event, add new ones
              const eventHeatIds = new Set(eventHeats.map((h) => h.id))
              const withoutEvent = prev.filter(
                (a) => !eventHeatIds.has(a.heatId),
              )
              return [...withoutEvent, ...assignmentsResult]
            })
          }
        } finally {
          setIsFetchingAssignments(false)
        }
      }
    } catch (_err) {
      toast.error("Failed to activate version")
    } finally {
      setIsRollingBack(false)
    }
  }

  // Get event defaults for selected event (with fallback to competition defaults)
  const selectedEventDefaults = useMemo(() => {
    const eventDefaults = eventDefaultsMap.get(selectedEventId)
    return {
      defaultHeatsCount:
        eventDefaults?.defaultHeatsCount ?? competitionDefaultHeats,
      defaultLaneShiftPattern:
        eventDefaults?.defaultLaneShiftPattern ?? competitionDefaultPattern,
      minHeatBuffer: eventDefaults?.minHeatBuffer ?? 2,
      // Raw values (null if not overridden at event level)
      rawDefaultHeatsCount: eventDefaults?.defaultHeatsCount ?? null,
      rawDefaultLaneShiftPattern:
        eventDefaults?.defaultLaneShiftPattern ?? null,
      rawMinHeatBuffer: eventDefaults?.minHeatBuffer ?? null,
    }
  }, [
    selectedEventId,
    eventDefaultsMap,
    competitionDefaultHeats,
    competitionDefaultPattern,
  ])

  // Compute occupied lanes per heat from athlete assignments
  const occupiedLanesByHeat = useMemo(() => {
    const map = new Map<number, Set<number>>()
    for (const heat of eventHeats) {
      const occupiedLanes = new Set<number>()
      for (const assignment of heat.assignments) {
        occupiedLanes.add(assignment.laneNumber)
      }
      map.set(heat.heatNumber, occupiedLanes)
    }
    return map
  }, [eventHeats])

  // Calculate rotation coverage for selected event
  const rotationCoverage = useMemo(() => {
    if (eventHeats.length === 0) {
      return {
        totalSlots: 0,
        coveredSlots: 0,
        coveragePercent: 0,
        gaps: [],
        overlaps: [],
      }
    }

    const heatsData = eventHeats.map((h) => {
      const base = {
        heatNumber: h.heatNumber,
        laneCount: h.venue?.laneCount ?? maxLanes,
      }
      // Include occupiedLanes if filtering is enabled
      if (filterEmptyLanes) {
        // Compute occupied lanes directly from heat assignments to ensure consistency
        const occupiedLanes = new Set<number>()
        for (const assignment of h.assignments) {
          occupiedLanes.add(assignment.laneNumber)
        }
        return {
          ...base,
          occupiedLanes,
        }
      }
      return base
    })

    return calculateCoverage(eventRotations, heatsData)
  }, [eventRotations, eventHeats, maxLanes, filterEmptyLanes])

  // Handle multi-select toggle
  function handleToggleSelect(membershipId: string, shiftKey: boolean) {
    setSelectedJudgeIds((prev) => {
      const next = new Set(prev)
      if (shiftKey && prev.size > 0) {
        // Range select - find indices using the sorted list
        const sortedJudges = judgesByAssignmentCount
        const lastSelected = Array.from(prev).pop()
        const lastIndex = sortedJudges.findIndex(
          (j) => j.membershipId === lastSelected,
        )
        const currentIndex = sortedJudges.findIndex(
          (j) => j.membershipId === membershipId,
        )
        if (lastIndex !== -1 && currentIndex !== -1) {
          const start = Math.min(lastIndex, currentIndex)
          const end = Math.max(lastIndex, currentIndex)
          for (let i = start; i <= end; i++) {
            const judge = sortedJudges[i]
            if (judge) {
              next.add(judge.membershipId)
            }
          }
          return next
        }
      }
      // Toggle single
      if (next.has(membershipId)) {
        next.delete(membershipId)
      } else {
        next.add(membershipId)
      }
      return next
    })
  }

  function clearSelection() {
    setSelectedJudgeIds(new Set())
  }

  // Handle assignment changes from heat cards
  function handleAssignmentChange(
    heatId: string,
    newAssignments: JudgeHeatAssignment[],
  ) {
    setAssignments((prev) => {
      // Remove old assignments for this heat, add new ones
      const withoutHeat = prev.filter((a) => a.heatId !== heatId)
      return [...withoutHeat, ...newAssignments]
    })
  }

  // Handle cross-heat moves
  function handleMoveAssignment(
    assignmentId: string,
    _sourceHeatId: string,
    targetHeatId: string,
    targetLane: number,
    assignment: JudgeHeatAssignment,
  ) {
    setAssignments((prev) => {
      // Remove from source heat
      const withoutSource = prev.filter((a) => a.id !== assignmentId)
      // Add to target heat with updated lane
      const movedAssignment: JudgeHeatAssignment = {
        ...assignment,
        heatId: targetHeatId,
        laneNumber: targetLane,
      }
      return [...withoutSource, movedAssignment]
    })
  }

  function handleGoToAthleteHeats() {
    navigate({
      to: "/compete/organizer/$competitionId/schedule",
      params: { competitionId },
    })
  }

  if (events.length === 0) {
    return (
      <div className="py-12 text-center">
        <p className="text-muted-foreground">
          No events have been added to this competition yet.
        </p>
        <p className="mt-2 text-sm text-muted-foreground">
          Add events in the Programming section before scheduling judges.
        </p>
      </div>
    )
  }

  return (
    <section className="space-y-8">
      {/* Header */}
      <div>
        <h2 className="text-xl font-semibold">Judging Schedule</h2>
        <p className="text-sm text-muted-foreground">
          Manage judge assignments with manual or rotation-based scheduling
        </p>
      </div>

      {/* Event Selector - Prominent placement (hidden when the parent
       * page already renders one, e.g. the AI scheduling page). */}
      {!hideEventSelector && (
        <div className="flex items-center gap-3">
          <label htmlFor="event-selector" className="text-sm font-medium">
            Event:
          </label>
          <Select value={selectedEventId} onValueChange={onEventChange}>
            <SelectTrigger id="event-selector" className="w-80">
              <SelectValue placeholder="Select event" />
            </SelectTrigger>
            <SelectContent>
              {events.map((event) => (
                <SelectItem key={event.id} value={event.id}>
                  {formatTrackOrder(event.trackOrder)} - {event.workout.name}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>
      )}

      {/* Published Assignments Section — only renders once there's an
       * active published version. Until the organizer publishes their
       * first draft, the section is hidden entirely (no empty-state
       * card) so the page focuses on building the schedule. */}
      {hasHeatScheduling && eventActiveVersion && (
        <section className="space-y-6">
          <h3 className="text-lg font-semibold">Published Assignments</h3>

          {/* Version Selector */}
          {eventVersionHistory.length > 0 && (
            <Card>
              <CardContent className="p-4">
                <div className="flex items-center gap-4">
                  <div className="flex-1">
                    <label
                      htmlFor="version-selector"
                      className="mb-1 block text-sm font-medium"
                    >
                      Assignment Version
                    </label>
                    <Select
                      value={selectedVersionId ?? ""}
                      onValueChange={handleVersionChange}
                      disabled={isRollingBack || isFetchingAssignments}
                    >
                      <SelectTrigger id="version-selector" className="w-full">
                        <SelectValue placeholder="Select version" />
                      </SelectTrigger>
                      <SelectContent>
                        {eventVersionHistory.map((version) => (
                          <SelectItem key={version.id} value={version.id}>
                            Version {version.version} - Published{" "}
                            {new Date(version.publishedAt).toLocaleDateString()}
                            {version.isActive && " (Active)"}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                    {selectedVersionId &&
                      eventVersionHistory.find(
                        (v) => v.id === selectedVersionId,
                      )?.notes && (
                        <p className="mt-1 text-xs text-muted-foreground">
                          {
                            eventVersionHistory.find(
                              (v) => v.id === selectedVersionId,
                            )?.notes
                          }
                        </p>
                      )}
                  </div>
                </div>
              </CardContent>
            </Card>
          )}

          {/* Overview */}
          <JudgeOverview
            events={events}
            heats={heats}
            judgeAssignments={assignments}
            filterEmptyLanes={filterEmptyLanes}
            onFilterEmptyLanesChange={setFilterEmptyLanes}
          />

          {/* Main content: judges panel + heats */}
          <div className="grid grid-cols-1 gap-6 lg:grid-cols-[280px_1fr]">
            {/* Available Judges Panel */}
            <Card className="lg:sticky lg:top-4 lg:self-start">
              <CardContent className="p-4">
                <div className="mb-3 flex items-center justify-between">
                  <h4 className="text-sm font-medium">Available Judges</h4>
                  {selectedJudgeIds.size > 0 && (
                    <button
                      type="button"
                      onClick={clearSelection}
                      className="text-xs text-muted-foreground hover:text-foreground"
                    >
                      Clear ({selectedJudgeIds.size})
                    </button>
                  )}
                </div>
                {judges.length === 0 ? (
                  <p className="py-4 text-center text-sm text-muted-foreground">
                    No judges have been added yet. Add volunteers with the Judge
                    role type in the Volunteers section above.
                  </p>
                ) : (
                  <>
                    {/* Search Input */}
                    <div className="relative mb-3">
                      <Search className="pointer-events-none absolute left-2.5 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
                      <Input
                        type="text"
                        placeholder="Search judges..."
                        value={availableJudgeSearch}
                        onChange={(e) =>
                          setAvailableJudgeSearch(e.target.value)
                        }
                        className="h-8 pl-8 text-sm"
                      />
                    </div>
                    <div className="max-h-[55vh] space-y-1.5 overflow-y-auto">
                      {filteredJudgesByAssignmentCount.map((judge) => (
                        <DraggableJudge
                          key={judge.membershipId}
                          volunteer={judge}
                          isSelected={selectedJudgeIds.has(judge.membershipId)}
                          onToggleSelect={handleToggleSelect}
                          selectedIds={selectedJudgeIds}
                          assignmentCount={judge.assignmentCount}
                          isAssignedToCurrentEvent={assignedJudgeIds.has(
                            judge.membershipId,
                          )}
                        />
                      ))}
                      {filteredJudgesByAssignmentCount.length === 0 &&
                        availableJudgeSearch && (
                          <p className="py-4 text-center text-sm text-muted-foreground">
                            No judges match "{availableJudgeSearch}"
                          </p>
                        )}
                    </div>
                  </>
                )}
              </CardContent>
            </Card>

            {/* Heats Grid */}
            <div className="space-y-4">
              {eventHeats.length === 0 ? (
                <OrganizerEmptyState
                  icon={CalendarDays}
                  title="No athlete heats yet"
                  description="Create athlete heats before assigning judges to lanes."
                  actionLabel="Go to athlete heats"
                  actionIcon={<CalendarDays className="mr-2 h-4 w-4" />}
                  onAction={handleGoToAthleteHeats}
                />
              ) : (
                eventHeats.map((heat) => (
                  <JudgeHeatCard
                    key={heat.id}
                    heat={heat}
                    competitionId={competitionId}
                    organizingTeamId={organizingTeamId}
                    unassignedVolunteers={unassignedJudges}
                    judgeAssignments={assignments.filter(
                      (a) => a.heatId === heat.id,
                    )}
                    maxLanes={maxLanes}
                    onDelete={() => {
                      // No-op: Heat deletion should be done in Schedule section
                      console.debug(
                        "Heat deletion is handled in Schedule section",
                      )
                    }}
                    onAssignmentChange={(newAssignments) =>
                      handleAssignmentChange(heat.id, newAssignments)
                    }
                    onMoveAssignment={handleMoveAssignment}
                    onScheduleRevisionPublished={refreshVersionData}
                    selectedJudgeIds={selectedJudgeIds}
                    onClearSelection={clearSelection}
                    filterEmptyLanes={filterEmptyLanes}
                    athleteOccupiedLanes={occupiedLanesByHeat.get(
                      heat.heatNumber,
                    )}
                  />
                ))
              )}
            </div>
          </div>
        </section>
      )}

      {hasHeatScheduling && (
        <section className="space-y-6">
          <div className="flex flex-wrap items-center justify-between gap-3">
            <h3 className="text-lg font-semibold">Rotations</h3>
            {/* Utilities cluster: event defaults (behind a drawer) +
             * printable schedule link. Flex-wrap so they drop to the
             * next row on narrow screens instead of cramping the heading. */}
            <div className="flex flex-wrap items-center gap-2">
              <Sheet>
                <SheetTrigger asChild>
                  <Button variant="outline" size="sm">
                    <Settings2 className="mr-2 h-4 w-4" />
                    Event defaults
                  </Button>
                </SheetTrigger>
                <SheetContent className="w-full overflow-y-auto sm:max-w-md">
                  <SheetHeader>
                    <SheetTitle>Event defaults</SheetTitle>
                    <SheetDescription>
                      Defaults for new rotations on this event. Leave fields
                      blank to inherit from the competition setting.
                    </SheetDescription>
                  </SheetHeader>
                  <div className="mt-4">
                    <EventDefaultsEditor
                      teamId={organizingTeamId}
                      competitionId={competitionId}
                      trackWorkoutId={selectedEventId}
                      defaultHeatsCount={
                        selectedEventDefaults.rawDefaultHeatsCount
                      }
                      defaultLaneShiftPattern={
                        selectedEventDefaults.rawDefaultLaneShiftPattern
                      }
                      minHeatBuffer={selectedEventDefaults.rawMinHeatBuffer}
                      competitionDefaultHeats={competitionDefaultHeats}
                      competitionDefaultPattern={competitionDefaultPattern}
                      onUpdateEventDefaults={overrides?.updateEventDefaults}
                    />
                  </div>
                </SheetContent>
              </Sheet>
              {heats.length > 0 && (
                <Button variant="outline" size="sm" asChild>
                  <Link
                    to="/compete/$slug/judges-schedule"
                    params={{ slug: competitionSlug }}
                  >
                    <ClipboardList className="mr-2 h-4 w-4" />
                    View printable schedule
                  </Link>
                </Button>
              )}
            </div>
          </div>

          {rotationsHeaderSlot}

          {/* Rotation Overview */}
          <RotationOverview
            rotations={eventRotations}
            coverage={rotationCoverage}
            eventName={selectedEvent?.workout.name ?? "Event"}
            teamId={organizingTeamId}
            trackWorkoutId={selectedEventId}
            hasActiveVersion={!!eventActiveVersion}
            nextVersionNumber={
              eventVersionHistory.length > 0
                ? (eventVersionHistory[0]?.version ?? 0) + 1
                : 1
            }
            onPublishSuccess={refreshVersionData}
            onPublishRotations={overrides?.publishRotations}
            leadingActions={rotationOverviewActionsSlot}
          />

          {/* Rotation Timeline */}
          {eventHeats.length > 0 ? (
            <RotationTimeline
              key={selectedEventId}
              competitionId={competitionId}
              teamId={organizingTeamId}
              trackWorkoutId={selectedEventId}
              eventName={selectedEvent?.workout.name ?? "Event"}
              heatsWithAssignments={eventHeats}
              laneCount={maxLanes}
              availableJudges={judges}
              initialRotations={eventRotations}
              eventLaneShiftPattern={
                selectedEventDefaults.defaultLaneShiftPattern
              }
              eventDefaultHeatsCount={selectedEventDefaults.defaultHeatsCount}
              minHeatBuffer={selectedEventDefaults.minHeatBuffer}
              filterEmptyLanes={filterEmptyLanes}
              onFilterEmptyLanesChange={setFilterEmptyLanes}
              onRotationsChange={setEventRotations}
              onUpdateJudgeRotation={overrides?.updateJudgeRotation}
              onDeleteVolunteerRotations={overrides?.deleteVolunteerRotations}
              onCreateJudgeRotation={overrides?.createJudgeRotation}
              onBatchCreateRotations={overrides?.batchCreateRotations}
              onBatchDeleteRotations={overrides?.batchDeleteRotations}
              onDeleteJudgeRotation={overrides?.deleteJudgeRotation}
              onBatchUpdateVolunteerRotations={
                overrides?.batchUpdateVolunteerRotations
              }
              onAdjustRotationsForOccupiedLanes={
                overrides?.adjustRotationsForOccupiedLanes
              }
            />
          ) : (
            <OrganizerEmptyState
              icon={CalendarDays}
              title="No athlete heats yet"
              description="Create athlete heats before building judge rotations."
              actionLabel="Go to athlete heats"
              actionIcon={<CalendarDays className="mr-2 h-4 w-4" />}
              onAction={handleGoToAthleteHeats}
            />
          )}
        </section>
      )}
    </section>
  )
}

"use client"

// @lat: [[crew#Judge Rotations]]

import { useRouter } from "@tanstack/react-router"
import { useServerFn } from "@tanstack/react-start"
import {
  CalendarDays,
  Loader2,
  MousePointerClick,
  Search,
  Send,
  Sparkles,
} from "lucide-react"
import { useEffect, useMemo, useState } from "react"
import { toast } from "sonner"
import { Button } from "@/components/ui/button"
import { Card, CardContent } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import { Textarea } from "@/components/ui/textarea"
import {
  type CrewJudgeRotationsPageData,
  publishCrewJudgeRotationsFn,
  saveCrewJudgeRotationsForVolunteerFn,
} from "@/server-fns/crew-judge-rotations-fns"
import { DraggableJudge } from "./draggable-judge"
import {
  autoFillWorkout,
  fillHeatWithAvailableJudges,
  getCrewJudgeName,
  gridCellsToRotationRows,
  type JudgeGridCell,
  JUDGE_GRID_LANE_SHIFT_PATTERN,
  rotationsToGridCells,
} from "./judge-grid-utils"
import { type HeatLaneAssignment, JudgeHeatCard } from "./judge-heat-card"
import { JudgeOverview } from "./judge-overview"

interface JudgeSchedulingContainerProps {
  eventId: string
  page: CrewJudgeRotationsPageData
  /** Currently selected workout ID (the wodsmith-start "event"). */
  selectedWorkoutId: string
  onWorkoutChange: (workoutId: string) => void
}

/**
 * Main container for Crew judge scheduling — a port of the wodsmith-start
 * organizer judging grid wired to Crew's rotation + version data layer. Grid
 * placements are kept as local cells and persisted per judge as single-heat
 * rotations; publishing materializes them through Crew's existing publish path.
 *
 * Built for FAST fill: drag a judge onto a lane, or pick an "active judge" and
 * click lanes to seat them, plus one-click bulk actions (fill a heat, seat a
 * judge down a whole lane across the workout, auto-distribute the whole grid).
 * Crew has no athlete/lane-occupancy data, so every lane of every heat is
 * always droppable and visible.
 */
export function JudgeSchedulingContainer({
  eventId,
  page,
  selectedWorkoutId,
  onWorkoutChange,
}: JudgeSchedulingContainerProps) {
  const router = useRouter()
  const saveRotations = useServerFn(saveCrewJudgeRotationsForVolunteerFn)
  const publishRotations = useServerFn(publishCrewJudgeRotationsFn)

  const { workouts, heats, judges } = page

  const [availableJudgeSearch, setAvailableJudgeSearch] = useState("")
  const [selectedJudgeIds, setSelectedJudgeIds] = useState<Set<string>>(
    new Set(),
  )
  const [publishNotes, setPublishNotes] = useState("")
  const [isPublishing, setIsPublishing] = useState(false)
  const [pendingJudgeIds, setPendingJudgeIds] = useState<Set<string>>(new Set())

  // Heats for the selected workout, sorted by heat number.
  const workoutHeats = useMemo(
    () =>
      heats
        .filter((h) => h.trackWorkoutId === selectedWorkoutId)
        .sort((a, b) => a.heatNumber - b.heatNumber),
    [heats, selectedWorkoutId],
  )

  // Max lanes across this workout's heats (fallback 10). Lane count comes from
  // each heat's location/venue, never from athletes.
  const maxLanes = useMemo(() => {
    const max = workoutHeats.reduce(
      (acc, heat) => Math.max(acc, heat.laneCount),
      0,
    )
    return max > 0 ? max : 10
  }, [workoutHeats])

  // Saved rotations for the selected workout, expanded into grid cells.
  const savedGridCells = useMemo(() => {
    const workoutRotations = page.rotations.filter(
      (rotation) => rotation.trackWorkoutId === selectedWorkoutId,
    )
    return rotationsToGridCells(workoutRotations, workoutHeats)
  }, [page.rotations, selectedWorkoutId, workoutHeats])

  // Local, editable grid state. Seeded from saved rotations and re-synced when
  // the loader data or selected workout changes.
  const [gridCells, setGridCells] = useState<JudgeGridCell[]>(savedGridCells)
  useEffect(() => {
    setGridCells(savedGridCells)
  }, [savedGridCells])

  const judgeByMembershipId = useMemo(
    () => new Map(judges.map((judge) => [judge.membershipId, judge])),
    [judges],
  )

  // Cells indexed by heat number for fast per-heat lookups.
  const cellsByHeatNumber = useMemo(() => {
    const map = new Map<number, JudgeGridCell[]>()
    for (const cell of gridCells) {
      const list = map.get(cell.heatNumber) ?? []
      list.push(cell)
      map.set(cell.heatNumber, list)
    }
    return map
  }, [gridCells])

  // Judges assigned somewhere in the current workout.
  const assignedJudgeIds = useMemo(
    () => new Set(gridCells.map((cell) => cell.membershipId)),
    [gridCells],
  )

  const unassignedJudges = useMemo(
    () => judges.filter((j) => !assignedJudgeIds.has(j.membershipId)),
    [judges, assignedJudgeIds],
  )

  // All judges sorted by assignment count (ascending — least assigned first).
  const judgesByAssignmentCount = useMemo(() => {
    const counts = new Map<string, number>()
    for (const judge of judges) counts.set(judge.membershipId, 0)
    for (const cell of gridCells) {
      counts.set(cell.membershipId, (counts.get(cell.membershipId) ?? 0) + 1)
    }
    return [...judges]
      .map((judge) => ({
        ...judge,
        assignmentCount: counts.get(judge.membershipId) ?? 0,
      }))
      .sort((a, b) => a.assignmentCount - b.assignmentCount)
  }, [judges, gridCells])

  const filteredJudgesByAssignmentCount = useMemo(() => {
    if (!availableJudgeSearch.trim()) return judgesByAssignmentCount
    const query = availableJudgeSearch.toLowerCase().trim()
    return judgesByAssignmentCount.filter((judge) =>
      getCrewJudgeName(judge).toLowerCase().includes(query),
    )
  }, [judgesByAssignmentCount, availableJudgeSearch])

  const selectedWorkout = workouts.find(
    (workout) => workout.id === selectedWorkoutId,
  )
  const activeVersion = selectedWorkoutId
    ? page.activeVersionByWorkout[selectedWorkoutId]
    : null

  // "Active judge" click-to-assign mode: when exactly one judge is selected,
  // clicking lanes seats/removes that judge — faster than dragging for filling
  // many cells.
  const activeJudgeId =
    selectedJudgeIds.size === 1 ? Array.from(selectedJudgeIds)[0] : null
  const activeJudge = activeJudgeId
    ? (judgeByMembershipId.get(activeJudgeId) ?? null)
    : null

  function markJudgePending(membershipId: string, pending: boolean) {
    setPendingJudgeIds((prev) => {
      const next = new Set(prev)
      if (pending) next.add(membershipId)
      else next.delete(membershipId)
      return next
    })
  }

  /**
   * Persist a set of judges' grid cells from a single already-computed `next`
   * cell set. Each save is scoped to one membership (Crew's save fn replaces
   * that judge's rotations for the workout). Optimistic; reverts on error.
   */
  async function persistJudges(
    membershipIds: string[],
    nextCells: JudgeGridCell[],
  ) {
    const uniqueIds = Array.from(new Set(membershipIds))
    if (uniqueIds.length === 0) return
    const previousCells = gridCells
    setGridCells(nextCells)
    for (const id of uniqueIds) markJudgePending(id, true)
    try {
      await Promise.all(
        uniqueIds.map((membershipId) =>
          saveRotations({
            data: {
              eventId,
              trackWorkoutId: selectedWorkoutId,
              membershipId,
              laneShiftPattern: JUDGE_GRID_LANE_SHIFT_PATTERN,
              rotations: gridCellsToRotationRows(
                nextCells.filter((cell) => cell.membershipId === membershipId),
              ),
            },
          }),
        ),
      )
      await router.invalidate()
    } catch (error) {
      setGridCells(previousCells)
      toast.error(
        error instanceof Error ? error.message : "Failed to save judges",
      )
    } finally {
      for (const id of uniqueIds) markJudgePending(id, false)
    }
  }

  function handleAssign(
    heatNumber: number,
    membershipId: string,
    laneNumber: number,
  ) {
    const next = gridCells.filter(
      (cell) =>
        // Replace any existing cell for this judge in this heat, and free the
        // target lane if another judge sat there.
        !(
          (cell.membershipId === membershipId &&
            cell.heatNumber === heatNumber) ||
          (cell.heatNumber === heatNumber && cell.laneNumber === laneNumber)
        ),
    )
    const displaced = gridCells.filter(
      (cell) =>
        cell.heatNumber === heatNumber &&
        cell.laneNumber === laneNumber &&
        cell.membershipId !== membershipId,
    )
    next.push({ membershipId, heatNumber, laneNumber })
    void persistJudges(
      [membershipId, ...displaced.map((cell) => cell.membershipId)],
      next,
    )
  }

  function handleBulkAssign(
    heatNumber: number,
    placements: Array<{ membershipId: string; laneNumber: number }>,
  ) {
    let next = gridCells.slice()
    const touched: string[] = []
    for (const placement of placements) {
      next = next.filter(
        (cell) =>
          !(
            (cell.membershipId === placement.membershipId &&
              cell.heatNumber === heatNumber) ||
            (cell.heatNumber === heatNumber &&
              cell.laneNumber === placement.laneNumber)
          ),
      )
      next.push({
        membershipId: placement.membershipId,
        heatNumber,
        laneNumber: placement.laneNumber,
      })
      touched.push(placement.membershipId)
    }
    void persistJudges(touched, next)
  }

  function handleRemove(heatNumber: number, membershipId: string) {
    const next = gridCells.filter(
      (cell) =>
        !(cell.membershipId === membershipId && cell.heatNumber === heatNumber),
    )
    void persistJudges([membershipId], next)
  }

  function handleMove(
    membershipId: string,
    sourceHeatNumber: number,
    targetHeatNumber: number,
    targetLane: number,
  ) {
    // Free the target lane (if occupied by someone else), drop the moving
    // judge's source + target cells, then seat them at the target.
    const displaced = gridCells.filter(
      (cell) =>
        cell.heatNumber === targetHeatNumber &&
        cell.laneNumber === targetLane &&
        cell.membershipId !== membershipId,
    )
    const next = gridCells.filter(
      (cell) =>
        !(
          (cell.membershipId === membershipId &&
            (cell.heatNumber === sourceHeatNumber ||
              cell.heatNumber === targetHeatNumber)) ||
          (cell.heatNumber === targetHeatNumber &&
            cell.laneNumber === targetLane)
        ),
    )
    next.push({
      membershipId,
      heatNumber: targetHeatNumber,
      laneNumber: targetLane,
    })
    void persistJudges(
      [membershipId, ...displaced.map((cell) => cell.membershipId)],
      next,
    )
  }

  /** Click an empty lane: seat the active judge there (or remove if it's them). */
  function handleLaneClick(heatNumber: number, laneNumber: number) {
    if (!activeJudgeId) return
    const occupant = gridCells.find(
      (cell) => cell.heatNumber === heatNumber && cell.laneNumber === laneNumber,
    )
    if (occupant?.membershipId === activeJudgeId) {
      handleRemove(heatNumber, activeJudgeId)
      return
    }
    handleAssign(heatNumber, activeJudgeId, laneNumber)
  }

  /** Seat the active judge in the same lane across every heat of the workout. */
  function handleAssignActiveJudgeToColumn(laneNumber: number) {
    if (!activeJudgeId) return
    const next = gridCells.filter(
      (cell) =>
        !(
          // clear this judge everywhere in the workout, plus free that lane for
          // every heat
          cell.membershipId === activeJudgeId || cell.laneNumber === laneNumber
        ),
    )
    const displaced = gridCells.filter(
      (cell) =>
        cell.laneNumber === laneNumber && cell.membershipId !== activeJudgeId,
    )
    for (const heat of workoutHeats) {
      if (laneNumber <= heat.laneCount) {
        next.push({
          membershipId: activeJudgeId,
          heatNumber: heat.heatNumber,
          laneNumber,
        })
      }
    }
    void persistJudges(
      [activeJudgeId, ...displaced.map((cell) => cell.membershipId)],
      next,
    )
  }

  /** Fill one heat's open lanes with the least-assigned available judges. */
  function handleFillHeat(heatNumber: number) {
    const heat = workoutHeats.find((h) => h.heatNumber === heatNumber)
    if (!heat) return
    const result = fillHeatWithAvailableJudges({
      cells: gridCells,
      heat,
      // Prefer judges not yet in this heat, least-assigned first.
      judgeOrder: judgesByAssignmentCount.map((judge) => judge.membershipId),
    })
    if (result.touched.length === 0) {
      toast.info("No open lanes or no available judges for this heat")
      return
    }
    void persistJudges(result.touched, result.cells)
  }

  /** Auto-distribute available judges across every open lane in the workout. */
  function handleAutoFillWorkout() {
    const result = autoFillWorkout({
      cells: gridCells,
      heats: workoutHeats,
      judgeOrder: judgesByAssignmentCount.map((judge) => judge.membershipId),
    })
    if (result.touched.length === 0) {
      toast.info("Grid is already full or there are no judges to seat")
      return
    }
    void persistJudges(result.touched, result.cells)
  }

  function handleToggleSelect(membershipId: string, shiftKey: boolean) {
    setSelectedJudgeIds((prev) => {
      const next = new Set(prev)
      if (shiftKey && prev.size > 0) {
        const sortedJudges = judgesByAssignmentCount
        const lastSelected = Array.from(prev).pop()
        const lastIndex = sortedJudges.findIndex(
          (j) => j.membershipId === lastSelected,
        )
        const currentIndex = sortedJudges.findIndex(
          (j) => j.membershipId === membershipId,
        )
        if (lastIndex !== -1 && currentIndex !== -1) {
          const start = Math.min(lastIndex, currentIndex)
          const end = Math.max(lastIndex, currentIndex)
          for (let i = start; i <= end; i++) {
            const judge = sortedJudges[i]
            if (judge) next.add(judge.membershipId)
          }
          return next
        }
      }
      if (next.has(membershipId)) next.delete(membershipId)
      else next.add(membershipId)
      return next
    })
  }

  function clearSelection() {
    setSelectedJudgeIds(new Set())
  }

  async function handlePublish() {
    if (!selectedWorkoutId) return
    setIsPublishing(true)
    try {
      await publishRotations({
        data: {
          eventId,
          trackWorkoutId: selectedWorkoutId,
          notes: publishNotes,
        },
      })
      toast.success("Published judge schedule")
      setPublishNotes("")
      await router.invalidate()
    } catch (error) {
      toast.error(
        error instanceof Error
          ? error.message
          : "Failed to publish judge schedule",
      )
    } finally {
      setIsPublishing(false)
    }
  }

  // Build per-heat assignment lists for the grid.
  function heatAssignments(heatNumber: number): HeatLaneAssignment[] {
    const cells = cellsByHeatNumber.get(heatNumber) ?? []
    return cells
      .map((cell) => {
        const volunteer = judgeByMembershipId.get(cell.membershipId)
        if (!volunteer) return null
        return {
          membershipId: cell.membershipId,
          laneNumber: cell.laneNumber,
          volunteer,
        }
      })
      .filter((value): value is HeatLaneAssignment => value !== null)
  }

  const isAnyPending = pendingJudgeIds.size > 0

  return (
    <section className="space-y-8">
      {/* Header */}
      <div className="flex flex-col gap-3 sm:flex-row sm:items-start sm:justify-between">
        <div>
          <h2 className="text-xl font-semibold">Judging Schedule</h2>
          <p className="text-sm text-muted-foreground">
            Drag judges onto lanes, or pick a judge and click lanes. Use the
            quick-fill actions to seat many at once, then publish.
          </p>
        </div>
        {selectedWorkoutId ? (
          <div className="flex flex-col gap-2 sm:min-w-80">
            <div className="flex items-center justify-between gap-3 text-sm">
              <span className="text-muted-foreground">
                {activeVersion ? "Published schedule" : "Not published"}
              </span>
              <Button
                type="button"
                onClick={handlePublish}
                disabled={isPublishing}
              >
                {isPublishing ? <Loader2 className="animate-spin" /> : <Send />}
                Publish
              </Button>
            </div>
            <Textarea
              value={publishNotes}
              onChange={(event) => setPublishNotes(event.target.value)}
              placeholder="Schedule notes"
              className="min-h-16"
            />
          </div>
        ) : null}
      </div>

      {/* Workout selector + workout-wide quick fill */}
      <div className="flex flex-wrap items-center gap-3">
        <label htmlFor="event-selector" className="text-sm font-medium">
          Workout:
        </label>
        <Select value={selectedWorkoutId} onValueChange={onWorkoutChange}>
          <SelectTrigger id="event-selector" className="w-80">
            <SelectValue placeholder="Select workout" />
          </SelectTrigger>
          <SelectContent>
            {workouts.map((workout) => (
              <SelectItem key={workout.id} value={workout.id}>
                Event {workout.trackOrder}: {workout.workout.name}
              </SelectItem>
            ))}
          </SelectContent>
        </Select>
        {selectedWorkout && workoutHeats.length > 0 ? (
          <Button
            type="button"
            variant="outline"
            size="sm"
            onClick={handleAutoFillWorkout}
            disabled={isAnyPending || unassignedJudges.length === 0}
          >
            <Sparkles className="mr-2 h-4 w-4" />
            Auto-fill workout
          </Button>
        ) : null}
        {isAnyPending ? (
          <span className="flex items-center gap-1 text-xs text-muted-foreground">
            <Loader2 className="h-3 w-3 animate-spin" />
            Saving
          </span>
        ) : null}
      </div>

      {/* Active-judge hint */}
      {activeJudge ? (
        <div className="flex items-center gap-2 rounded-md border border-primary/40 bg-primary/5 px-3 py-2 text-sm">
          <MousePointerClick className="h-4 w-4 text-primary" />
          <span>
            Click any lane to seat{" "}
            <span className="font-medium">{getCrewJudgeName(activeJudge)}</span>
            . Use a lane's column button to seat them down that lane for the
            whole workout.
          </span>
          <button
            type="button"
            onClick={clearSelection}
            className="ml-auto text-xs text-muted-foreground hover:text-foreground"
          >
            Done
          </button>
        </div>
      ) : null}

      {/* Overview */}
      <JudgeOverview workouts={workouts} heats={heats} gridCells={gridCells} />

      {/* Main content: judges panel + heats */}
      <div className="grid grid-cols-1 gap-6 lg:grid-cols-[280px_1fr]">
        {/* Available Judges Panel */}
        <Card className="lg:sticky lg:top-4 lg:self-start">
          <CardContent className="p-4">
            <div className="mb-3 flex items-center justify-between">
              <h4 className="text-sm font-medium">Available Judges</h4>
              {selectedJudgeIds.size > 0 && (
                <button
                  type="button"
                  onClick={clearSelection}
                  className="text-xs text-muted-foreground hover:text-foreground"
                >
                  Clear ({selectedJudgeIds.size})
                </button>
              )}
            </div>
            {judges.length === 0 ? (
              <p className="py-4 text-center text-sm text-muted-foreground">
                No judges have been added yet. Add volunteers with the Judge
                role type in the Roster section.
              </p>
            ) : (
              <>
                <p className="mb-3 text-xs text-muted-foreground">
                  Click a judge to enter click-to-assign mode, or drag them onto
                  a lane. Shift-click to multi-select for bulk drags.
                </p>
                {/* Search Input */}
                <div className="relative mb-3">
                  <Search className="pointer-events-none absolute left-2.5 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
                  <Input
                    type="text"
                    placeholder="Search judges..."
                    value={availableJudgeSearch}
                    onChange={(e) => setAvailableJudgeSearch(e.target.value)}
                    className="h-8 pl-8 text-sm"
                  />
                </div>
                <div className="max-h-[55vh] space-y-1.5 overflow-y-auto">
                  {filteredJudgesByAssignmentCount.map((judge) => (
                    <DraggableJudge
                      key={judge.membershipId}
                      volunteer={judge}
                      isSelected={selectedJudgeIds.has(judge.membershipId)}
                      onToggleSelect={handleToggleSelect}
                      selectedIds={selectedJudgeIds}
                      assignmentCount={judge.assignmentCount}
                      isAssignedToCurrentEvent={assignedJudgeIds.has(
                        judge.membershipId,
                      )}
                    />
                  ))}
                  {filteredJudgesByAssignmentCount.length === 0 &&
                    availableJudgeSearch && (
                      <p className="py-4 text-center text-sm text-muted-foreground">
                        No judges match "{availableJudgeSearch}"
                      </p>
                    )}
                </div>
              </>
            )}
          </CardContent>
        </Card>

        {/* Heats Grid */}
        <div className="space-y-4">
          {!selectedWorkout ? (
            <EmptyHeats message="Select a workout to schedule judges." />
          ) : workoutHeats.length === 0 ? (
            <EmptyHeats message="Create the heat schedule before assigning judges to lanes." />
          ) : (
            workoutHeats.map((heat) => (
              <JudgeHeatCard
                key={heat.id}
                heat={heat}
                unassignedVolunteers={unassignedJudges}
                assignments={heatAssignments(heat.heatNumber)}
                maxLanes={maxLanes}
                activeJudgeId={activeJudgeId}
                onAssign={(membershipId, laneNumber) =>
                  handleAssign(heat.heatNumber, membershipId, laneNumber)
                }
                onBulkAssign={(placements) =>
                  handleBulkAssign(heat.heatNumber, placements)
                }
                onRemove={(membershipId) =>
                  handleRemove(heat.heatNumber, membershipId)
                }
                onMove={(membershipId, sourceHeatId, targetLane) => {
                  const sourceHeat = workoutHeats.find(
                    (h) => h.id === sourceHeatId,
                  )
                  handleMove(
                    membershipId,
                    sourceHeat?.heatNumber ?? heat.heatNumber,
                    heat.heatNumber,
                    targetLane,
                  )
                }}
                onLaneClick={(laneNumber) =>
                  handleLaneClick(heat.heatNumber, laneNumber)
                }
                onAssignActiveToColumn={handleAssignActiveJudgeToColumn}
                onFillHeat={() => handleFillHeat(heat.heatNumber)}
                isPending={isAnyPending}
                selectedJudgeIds={selectedJudgeIds}
                onClearSelection={clearSelection}
              />
            ))
          )}
        </div>
      </div>
    </section>
  )
}

function EmptyHeats({ message }: { message: string }) {
  return (
    <div className="rounded-md border bg-card p-8 text-center shadow-sm">
      <CalendarDays className="mx-auto mb-3 h-8 w-8 text-muted-foreground" />
      <p className="text-sm text-muted-foreground">{message}</p>
    </div>
  )
}

